ALTER TABLE public.ecf_sequence_allocations ADD CONSTRAINT ecf_sequence_allocations_status_check CHECK ((status = ANY (ARRAY['active'::text, 'exhausted'::text, 'revoked'::text])));
ALTER TABLE public.ecf_sequence_allocations ADD CONSTRAINT ecf_sequence_allocations_pkey PRIMARY KEY (id);
ALTER TABLE public.ecf_sequence_allocations ADD CONSTRAINT ecf_sequence_allocations_tenant_id_fkey FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE;
ALTER TABLE public.ecf_e32_readiness_evidence ADD CONSTRAINT ecf_e32_readiness_requires_full_approval CHECK (((approved_at IS NULL) OR ((e32_validated IS TRUE) AND (rfce_validated IS TRUE) AND (resumen_validated IS TRUE))));
ALTER TABLE public.ecf_e32_readiness_evidence ADD CONSTRAINT ecf_e32_readiness_evidence_pkey PRIMARY KEY (id);
ALTER TABLE public.ecf_batches ADD CONSTRAINT ecf_batches_status_check CHECK ((status = ANY (ARRAY['pending'::text, 'submitted'::text, 'accepted'::text, 'rejected'::text, 'retryable_error'::text, 'terminal_error'::text])));
ALTER TABLE public.ecf_batches ADD CONSTRAINT ecf_batches_pkey PRIMARY KEY (id);
ALTER TABLE public.ecf_batches ADD CONSTRAINT ecf_batches_tenant_id_fkey FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE;
ALTER TABLE public.ecf_documents ADD CONSTRAINT ecf_documents_batch_id_fkey FOREIGN KEY (batch_id) REFERENCES ecf_batches(id) ON DELETE SET NULL;
