ALTER TABLE public.ecf_documents ADD CONSTRAINT ecf_documents_rejection_scope_check CHECK (((rejection_scope IS NULL) OR (rejection_scope = ANY (ARRAY['individual'::text, 'batch'::text]))));
ALTER TABLE public.ecf_documents ADD CONSTRAINT ecf_documents_status_check CHECK ((status = ANY (ARRAY['pending_offline'::text, 'pending_sync'::text, 'queued'::text, 'signed'::text, 'submitted'::text, 'accepted'::text, 'rejected'::text, 'retryable_error'::text, 'terminal_error'::text, 'pending_configuration'::text, 'pending_rfce_batch'::text])));
ALTER TABLE public.fiscal_outbox ADD CONSTRAINT fiscal_outbox_status_check CHECK ((status = ANY (ARRAY['queued'::text, 'processing'::text, 'retryable_error'::text, 'terminal_error'::text, 'done'::text, 'blocked_configuration'::text])));
ALTER TABLE public.ecf_document_events ADD CONSTRAINT ecf_document_events_to_status_check CHECK ((to_status = ANY (ARRAY['pending_offline'::text, 'pending_sync'::text, 'queued'::text, 'signed'::text, 'submitted'::text, 'accepted'::text, 'rejected'::text, 'retryable_error'::text, 'terminal_error'::text, 'pending_configuration'::text, 'pending_rfce_batch'::text])));
ALTER TABLE public.ecf_document_events ADD CONSTRAINT ecf_document_events_from_status_check CHECK (((from_status IS NULL) OR (from_status = ANY (ARRAY['pending_offline'::text, 'pending_sync'::text, 'queued'::text, 'signed'::text, 'submitted'::text, 'accepted'::text, 'rejected'::text, 'retryable_error'::text, 'terminal_error'::text, 'pending_configuration'::text, 'pending_rfce_batch'::text]))));
ALTER TABLE public.cierres_operativos ADD CONSTRAINT cierres_operativos_efectivo_inicial_bounds CHECK (((efectivo_inicial >= (0)::numeric) AND (efectivo_inicial <= 9999999999.99)));
ALTER TABLE public.digital_orders ADD CONSTRAINT digital_orders_order_type_check CHECK ((order_type = ANY (ARRAY['takeout'::text, 'in_store'::text])));
ALTER TABLE public.tenant_order_counters ADD CONSTRAINT tenant_order_counters_pkey PRIMARY KEY (tenant_id);
ALTER TABLE public.tenant_order_counters ADD CONSTRAINT tenant_order_counters_tenant_id_fkey FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE;
ALTER TABLE public.tenants ADD CONSTRAINT tenants_payment_day_of_month_check CHECK (((payment_day_of_month IS NULL) OR ((payment_day_of_month >= 1) AND (payment_day_of_month <= 31))));